import { useEffect, useRef, useState, useCallback } from 'react';
import { useSimulationStore } from '../store';
import { motion, AnimatePresence } from 'framer-motion';

// ─── Particle type ────────────────────────────────────────────────────────────
interface Particle {
  x: number; y: number;
  vx: number; vy: number;
  life: number;           // 1.0 → 0.0
  color: string;
}

// ─── Toolbar tool type ────────────────────────────────────────────────────────
type Tool = 'cursor' | 'crosshair' | 'hline' | 'vline';

const TOOLBAR_TOOLS: { id: Tool; label: string; icon: string }[] = [
  { id: 'cursor',    label: 'Cursor',    icon: '↖' },
  { id: 'crosshair', label: 'Crosshair', icon: '⊕' },
  { id: 'hline',     label: 'H-Line',    icon: '—' },
  { id: 'vline',     label: 'V-Line',    icon: '|' },
];

export default function MainArea() {
  const {
    currentPrice, isRunning, priceHistory, chartType, setChartType,
    simulationSpeed, setSimulationSpeed, chartTrades,
    timeframe, setTimeframe,
  } = useSimulationStore();

  const TIMEFRAMES = ['1s', '1m', '5m', '1h'] as const;

  const visibleCandlesMap: Record<string, number> = {
    '1s': 30, '1m': 60, '5m': 80, '1h': 100,
  };

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const requestRef = useRef<number>();
  const particlesRef = useRef<Particle[]>([]);

  // ─── Mapping refs (To convert between Canvas Pixels and Prices) ───────────
  const toXRef   = useRef<((index: number) => number) | null>(null);
  const toYRef   = useRef<((price: number) => number) | null>(null);
  const fromXRef = useRef<((canvasX: number) => number) | null>(null);
  const fromYRef = useRef<((canvasY: number) => number) | null>(null);

  // ─── React state (UI) ─────────────────────────────────────────────────────
  const [activeTool, setActiveTool] = useState<Tool>('cursor');
  const [hLines, setHLines]         = useState<number[]>([]);
  const [vLines, setVLines]         = useState<number[]>([]);
  const [showSMA, setShowSMA]       = useState(false);
  const [isToolbarOpen, setIsToolbarOpen] = useState(false);
  const [mousePos, setMousePos]     = useState<{ x: number; y: number } | null>(null);
  const [hoveredPrice, setHoveredPrice] = useState<number | null>(null);

  // ─── Fast refs for the animation loop (prevents re-renders) ───────────────
  const priceHistoryRef  = useRef(priceHistory);
  const visibleHistoryRef= useRef(priceHistory); // slice of history
  const chartTradesRef   = useRef(chartTrades);
  const currentPriceRef  = useRef(currentPrice);
  const mousePosRef      = useRef(mousePos);

  const activeToolRef = useRef(activeTool);
  const hLinesRef     = useRef(hLines);
  const vLinesRef     = useRef(vLines);
  const showSMARef    = useRef(showSMA);

  useEffect(() => { priceHistoryRef.current = priceHistory; }, [priceHistory]);
  useEffect(() => { chartTradesRef.current = chartTrades; }, [chartTrades]);
  useEffect(() => { currentPriceRef.current = currentPrice; }, [currentPrice]);
  useEffect(() => { mousePosRef.current = mousePos; }, [mousePos]);
  useEffect(() => { activeToolRef.current = activeTool; }, [activeTool]);
  useEffect(() => { hLinesRef.current = hLines; }, [hLines]);
  useEffect(() => { vLinesRef.current = vLines; }, [vLines]);
  useEffect(() => { showSMARef.current = showSMA; }, [showSMA]);

  // Particles generator
  useEffect(() => {
    if (priceHistory.length < 2) return;
    const last = priceHistory[priceHistory.length - 1];
    const prev = priceHistory[priceHistory.length - 2];
    if (last.close !== prev.close) {
      const color = last.close > prev.close ? '#00ff88' : '#ff4d4d';
      for (let i = 0; i < 5; i++) {
        particlesRef.current.push({
          x: 0, y: 0,
          vx: (Math.random() - 0.5) * 4,
          vy: (Math.random() - 0.5) * 4,
          life: 1.0,
          color,
        });
      }
    }
  }, [priceHistory]);

  const draw = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const W = canvas.clientWidth;
    const H = canvas.clientHeight;
    if (canvas.width !== W || canvas.height !== H) {
      canvas.width = W;
      canvas.height = H;
    }

    ctx.clearRect(0, 0, W, H);

    const history = priceHistoryRef.current;
    if (history.length === 0) {
      requestRef.current = requestAnimationFrame(draw);
      return;
    }

    const maxVisible = visibleCandlesMap[timeframe] || 30;
    const vh = history.slice(-maxVisible);
    visibleHistoryRef.current = vh;

    const prices = vh.flatMap((c) => [c.high, c.low]);
    const pMinBase = prices.length ? Math.min(...prices) : currentPriceRef.current * 0.99;
    const pMaxBase = prices.length ? Math.max(...prices) : currentPriceRef.current * 1.01;

    let pSpan = pMaxBase - pMinBase;
    if (pSpan === 0) pSpan = currentPriceRef.current * 0.001; // Защита от черного экрана!

    const pMin = pMinBase - pSpan * 0.1;
    const pMax = pMaxBase + pSpan * 0.1;
    pSpan = pMax - pMin;

    const PAD = { top: 40, bottom: 40, left: 20, right: 60 };
    const chartW = W - PAD.left - PAD.right;
    const chartH = H - PAD.top - PAD.bottom;

    // ─── Хелперы координат ───
    const toX = (i: number) => PAD.left + (i / (vh.length - 1)) * chartW;
    const toY = (p: number) => PAD.top + chartH - ((p - pMin) / pSpan) * chartH;
    const fromY = (cy: number) => pMin + ((PAD.top + chartH - cy) / chartH) * pSpan;
    const fromX = (cx: number) => ((cx - PAD.left) / chartW) * (vh.length - 1);

    toXRef.current   = toX;
    toYRef.current   = toY;
    fromYRef.current = fromY;
    fromXRef.current = fromX;

    // ── Background Grid ──
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.03)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let i = 0; i <= 5; i++) {
      const y = PAD.top + (chartH / 5) * i;
      ctx.moveTo(PAD.left, y);
      ctx.lineTo(PAD.left + chartW, y);
    }
    for (let i = 0; i <= 10; i++) {
      const x = PAD.left + (chartW / 10) * i;
      ctx.moveTo(x, PAD.top);
      ctx.lineTo(x, PAD.top + chartH);
    }
    ctx.stroke();

    // ── SMA 20 (Оранжевая линия) ──
    if (showSMARef.current && vh.length > 0) {
      ctx.save();
      ctx.beginPath();
      ctx.strokeStyle = '#ff9900';
      ctx.lineWidth = 2;
      ctx.shadowColor = '#ff9900';
      ctx.shadowBlur = 8;
      let firstSMA = true;
      const offsetSMA = priceHistoryRef.current.length - vh.length;

      for (let vi = 0; vi < vh.length; vi++) {
        const globalIdx = offsetSMA + vi;
        if (globalIdx < 19) continue;
        let sum = 0;
        for (let j = 0; j < 20; j++) sum += history[globalIdx - j].close;
        const sma = sum / 20;
        const x = toX(vi);
        const y = toY(sma);
        if (firstSMA) { ctx.moveTo(x, y); firstSMA = false; }
        else { ctx.lineTo(x, y); }
      }
      ctx.stroke();
      ctx.restore();
    }

    // ── V-Lines (Вертикальные) ──
    ctx.save();
    ctx.strokeStyle = '#00ffc8';
    ctx.lineWidth   = 1.5;
    ctx.setLineDash([6, 6]);
    ctx.shadowColor = '#00ffc8';
    ctx.shadowBlur  = 6;
    const offsetVLine = priceHistoryRef.current.length - vh.length;
    for (const absIndex of vLinesRef.current) {
      const vi = absIndex - offsetVLine;
      if (vi >= 0 && vi < vh.length) {
        const x = toX(vi);
        ctx.beginPath(); ctx.moveTo(x, PAD.top); ctx.lineTo(x, H - PAD.bottom); ctx.stroke();
      }
    }
    ctx.setLineDash([]);
    ctx.restore();

    // ── H-Lines (Горизонтальные) ──
    ctx.save();
    ctx.strokeStyle = '#a78bfa';
    ctx.lineWidth   = 1.5;
    ctx.setLineDash([6, 6]);
    ctx.shadowColor = '#a78bfa';
    ctx.shadowBlur  = 6;
    for (const p of hLinesRef.current) {
      const y = toY(p);
      ctx.beginPath(); ctx.moveTo(PAD.left, y); ctx.lineTo(PAD.left + chartW, y); ctx.stroke();
    }
    ctx.setLineDash([]);
    ctx.restore();

    // ── Chart ──
    if (chartType === 'CANDLE') {
      const candleW = (chartW / maxVisible) * 0.6;
      for (let i = 0; i < vh.length; i++) {
        const c = vh[i];
        const x = toX(i);
        const yO = toY(c.open);
        const yC = toY(c.close);
        const yH = toY(c.high);
        const yL = toY(c.low);
        const isUp = c.close >= c.open;
        const color = isUp ? '#00ff88' : '#ff4d4d';

        ctx.strokeStyle = color;
        ctx.lineWidth = 1.5;
        ctx.beginPath(); ctx.moveTo(x, yH); ctx.lineTo(x, yL); ctx.stroke();

        ctx.fillStyle = isUp ? '#0d1117' : color;
        const topY = Math.min(yO, yC);
        const botY = Math.max(yO, yC);
        const hC = Math.max(botY - topY, 1);
        ctx.fillRect(x - candleW / 2, topY, candleW, hC);
        ctx.strokeRect(x - candleW / 2, topY, candleW, hC);
      }
    } else {
      ctx.save();
      ctx.strokeStyle = '#00ff88';
      ctx.lineWidth = 2;
      ctx.shadowColor = '#00ff88';
      ctx.shadowBlur = 10;
      ctx.beginPath();
      for (let i = 0; i < vh.length; i++) {
        const x = toX(i);
        const y = toY(vh[i].close);
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      }
      ctx.stroke();

      ctx.lineTo(toX(vh.length - 1), PAD.top + chartH);
      ctx.lineTo(toX(0), PAD.top + chartH);
      ctx.fillStyle = 'rgba(0, 255, 136, 0.05)';
      ctx.fill();
      ctx.restore();
    }

    // ── Trade markers ──
    const offsetTrade = priceHistoryRef.current.length - vh.length;
    for (const trade of chartTradesRef.current) {
      const vi = trade.historyIndex - offsetTrade;
      if (vi < 0 || vi >= vh.length) continue;

      const mx = toX(vi);
      const my = toY(trade.price);
      const isBuy = trade.type === 'BUY';
      const color = isBuy ? '#00ff88' : '#ff4d4d';
      const cy = isBuy ? my + 16 : my - 16;

      ctx.save();
      ctx.shadowColor = color;
      ctx.shadowBlur  = 10;
      ctx.fillStyle   = color;
      ctx.beginPath(); ctx.arc(mx, cy, 8, 0, Math.PI * 2); ctx.fill();
      ctx.shadowBlur = 0;
      ctx.font = 'bold 10px sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.strokeText(isBuy ? 'B' : 'S', mx, cy + 0.5);
      ctx.fillStyle = '#ffffff';
      ctx.fillText(isBuy ? 'B' : 'S', mx, cy + 0.5);
      ctx.restore();
    }

    // ── Particles ──
    const lastIdx = vh.length - 1;
    if (lastIdx >= 0) {
      const px = toX(lastIdx);
      const py = toY(vh[lastIdx].close);
      for (let i = particlesRef.current.length - 1; i >= 0; i--) {
        const p = particlesRef.current[i];
        p.x += p.vx; p.y += p.vy; p.life -= 0.05;
        if (p.life <= 0) { particlesRef.current.splice(i, 1); continue; }
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.beginPath(); ctx.arc(px + p.x, py + p.y, 2, 0, Math.PI * 2); ctx.fill();
      }
      ctx.globalAlpha = 1.0;
    }

    // ── Crosshair ──
    const mp = mousePosRef.current;
    if (mp && activeToolRef.current !== 'cursor') {
      ctx.save();
      ctx.strokeStyle = 'rgba(255,255,255,0.4)';
      ctx.lineWidth = 0.5;
      ctx.setLineDash([4, 4]);
      ctx.beginPath();
      if (activeToolRef.current === 'crosshair' || activeToolRef.current === 'vline') {
        ctx.moveTo(mp.x, PAD.top); ctx.lineTo(mp.x, PAD.top + chartH);
      }
      if (activeToolRef.current === 'crosshair' || activeToolRef.current === 'hline') {
        ctx.moveTo(PAD.left, mp.y); ctx.lineTo(PAD.left + chartW, mp.y);
      }
      ctx.stroke();
      ctx.restore();
    }

    requestRef.current = requestAnimationFrame(draw);
  }, [chartType, timeframe]);

  useEffect(() => {
    requestRef.current = requestAnimationFrame(draw);
    return () => cancelAnimationFrame(requestRef.current!);
  }, [draw]);

  // ─── Interaction ────────────────────────────────────────────────────────────

  const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setMousePos({ x, y });

    const fromY = fromYRef.current;
    if (fromY) setHoveredPrice(fromY(y));
  }, []);

  const handleMouseLeave = useCallback(() => {
    setMousePos(null);
    setHoveredPrice(null);
  }, []);

  const handleClick = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;

    if (activeToolRef.current === 'hline') {
      const fromY = fromYRef.current;
      if (!fromY) return;
      const canvasY = e.clientY - rect.top;
      const clickedPrice = fromY(canvasY);
      setHLines((prev) => [...prev, parseFloat(clickedPrice.toFixed(2))]);
      setActiveTool('cursor'); // Сбрасываем инструмент после клика
    } else if (activeToolRef.current === 'vline') {
      const fromX = fromXRef.current;
      if (!fromX) return;
      const canvasX = e.clientX - rect.left;
      const clickedIndex = Math.round(fromX(canvasX));
      const absIndex = (priceHistoryRef.current.length - visibleHistoryRef.current.length) + clickedIndex;
      setVLines((prev) => [...prev, absIndex]);
      setActiveTool('cursor'); // Сбрасываем инструмент после клика
    }
  }, []);

  const cursorStyle: Record<Tool, string> = {
    cursor:    'default',
    crosshair: 'crosshair',
    hline:     'row-resize',
    vline:     'col-resize',
  };

  return (
    <main className="flex-1 flex flex-col relative min-w-0">

      {/* ── TOP CONTROLS ── */}
      <div className="absolute top-4 right-4 z-10 flex gap-2">
        <div className="flex bg-[#161b22]/80 backdrop-blur-md rounded-lg p-1 border border-white/10 shadow-xl">
          {(['LINE', 'CANDLE'] as const).map((type) => (
            <button
              key={type}
              onClick={() => setChartType(type)}
              className={`px-3 py-1.5 rounded-md text-xs font-bold tracking-widest transition-all ${
                chartType === type
                  ? 'bg-violet-500/20 text-violet-400'
                  : 'text-white/40 hover:text-white'
              }`}
            >
              {type}
            </button>
          ))}
        </div>
        <div className="flex bg-[#161b22]/80 backdrop-blur-md rounded-lg p-1 border border-white/10 shadow-xl">
          {TIMEFRAMES.map((tf) => (
            <button
              key={tf}
              onClick={() => setTimeframe(tf)}
              className={`px-3 py-1.5 rounded-md text-xs font-bold font-mono transition-all ${
                timeframe === tf
                  ? 'bg-[#00ff88]/20 text-[#00ff88]'
                  : 'text-white/40 hover:text-white'
              }`}
            >
              {tf}
            </button>
          ))}
        </div>
      </div>

      {/* ── CANVAS AREA ── */}
      <div
        ref={containerRef}
        className="flex-1 relative overflow-hidden"
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        onClick={handleClick}
        style={{ cursor: cursorStyle[activeTool] }}
      >
        <canvas ref={canvasRef} className="absolute inset-0 w-full h-full block" />

        {/* ── HUD OVERLAYS ── */}
        <div className="absolute right-12 bottom-16 bg-[#0d1117]/80 backdrop-blur-md px-3 py-2 rounded-lg border border-[#00ff88]/20 flex flex-col items-end pointer-events-none shadow-[0_0_20px_rgba(0,255,136,0.1)]">
          <span className="text-[#00ff88] font-mono text-xl font-bold tracking-tight">
            ${currentPrice.toFixed(2)}
          </span>
          <span className="text-white/40 text-[10px] uppercase tracking-widest font-semibold mt-0.5">
            Market Price
          </span>
        </div>

        {/* Hovered Price Tag */}
        {hoveredPrice !== null && (activeTool === 'crosshair' || activeTool === 'hline') && mousePos && (
          <div
            className="absolute left-10 bg-violet-500/20 backdrop-blur-md px-2 py-1 rounded text-violet-400 font-mono text-xs border border-violet-500/40 pointer-events-none"
            style={{ top: mousePos.y - 12 }}
          >
            ${hoveredPrice.toFixed(2)}
          </div>
        )}

        {/* ── Collapsible Toolbar ── */}
        <div className="absolute left-4 top-4 z-20 flex flex-col gap-2">
          <button
            onClick={() => setIsToolbarOpen(!isToolbarOpen)}
            className={`w-10 h-10 flex items-center justify-center rounded-xl border transition-all shadow-lg ${
              isToolbarOpen 
                ? 'bg-[#00ff88]/20 border-[#00ff88]/50 text-[#00ff88]' 
                : 'bg-[#161b22]/80 border-white/10 text-white/60 hover:text-white hover:bg-white/5'
            }`}
            title="Tools"
          >
            🛠️
          </button>

          <AnimatePresence>
            {isToolbarOpen && (
              <motion.div
                initial={{ opacity: 0, x: -10, scale: 0.95 }}
                animate={{ opacity: 1, x: 0, scale: 1 }}
                exit={{ opacity: 0, x: -10, scale: 0.95 }}
                transition={{ duration: 0.2 }}
                className="flex flex-col gap-1.5 p-1.5 rounded-xl bg-[#0d1117]/90 backdrop-blur-md border border-white/10 shadow-2xl"
              >
                {TOOLBAR_TOOLS.map((tool) => {
                  const isActive = activeTool === tool.id;
                  return (
                    <button
                      key={tool.id}
                      onClick={(e) => { e.stopPropagation(); setActiveTool(tool.id); }}
                      title={tool.label}
                      className={`w-8 h-8 flex flex-col items-center justify-center rounded-lg transition-all gap-0.5 group ${
                        isActive
                          ? 'bg-[#00ff88]/15 border border-[#00ff88]/40 text-[#00ff88] shadow-[0_0_12px_rgba(0,255,136,0.2)]'
                          : 'border border-transparent text-white/30 hover:text-white/70 hover:bg-white/5 hover:border-white/10'
                      }`}
                    >
                      <span className="text-sm leading-none">{tool.icon}</span>
                    </button>
                  );
                })}

                <div className="w-full h-px bg-white/10 my-0.5" />

                {/* SMA Toggle */}
                <button
                  onClick={(e) => { e.stopPropagation(); setShowSMA(!showSMA); }}
                  title="Toggle SMA 20"
                  className={`w-8 h-8 flex items-center justify-center rounded-lg transition-all text-xs font-bold font-mono ${
                    showSMA
                      ? 'bg-[#ff9900]/20 text-[#ff9900] border border-[#ff9900]/40'
                      : 'bg-transparent text-white/30 border border-transparent hover:text-white/70 hover:bg-white/5'
                  }`}
                >
                  S
                </button>

                {/* Clear Lines button */}
                {(hLines.length > 0 || vLines.length > 0) && (
                  <>
                    <div className="w-full h-px bg-white/10 my-0.5" />
                    <button
                      onClick={(e) => { e.stopPropagation(); setHLines([]); setVLines([]); }}
                      title="Clear all Lines"
                      className="w-8 h-8 flex items-center justify-center rounded-lg border border-transparent text-white/20 hover:text-[#ff4d4d] hover:bg-[#ff4d4d]/10 hover:border-[#ff4d4d]/20 transition-all text-xs"
                    >
                      ✕
                    </button>
                  </>
                )}
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        {/* Lines count badge */}
        {(hLines.length > 0 || vLines.length > 0) && (
          <div className="absolute left-16 top-4 z-10 flex items-center gap-1.5 px-2 py-1 rounded-lg bg-[#0d1117]/70 border border-[#a78bfa]/20 backdrop-blur-sm pointer-events-none">
            <span className="w-1.5 h-1.5 rounded-full bg-[#a78bfa]" />
            <span className="text-[9px] font-mono text-[#a78bfa]/70 uppercase tracking-widest">
              {hLines.length + vLines.length} line{(hLines.length + vLines.length) > 1 ? 's' : ''}
            </span>
          </div>
        )}
      </div>

      {/* ── BOTTOM SPEED CONTROL ── */}
      <div className="h-14 bg-[#161b22]/90 backdrop-blur-md border-t border-white/10 flex items-center justify-between px-6 shrink-0">
        <div className="flex items-center gap-4">
          <span className="text-[10px] text-white/40 uppercase tracking-widest font-semibold">
            Engine Speed
          </span>
          <input
            type="range"
            min={1}
            max={60}
            value={simulationSpeed}
            onChange={(e) => setSimulationSpeed(Number(e.target.value))}
            className="w-48 h-1 appearance-none rounded-full outline-none cursor-pointer"
            style={{
              background: `linear-gradient(to right, #a78bfa ${(simulationSpeed / 60) * 100}%, rgba(255,255,255,0.1) ${(simulationSpeed / 60) * 100}%)`,
            }}
          />
          <span className="text-xs text-violet-400 font-mono w-8">
            {simulationSpeed}x
          </span>
        </div>
      </div>
    </main>
  );
}
